  //            ^inv(Set)  ^inv(map) ^bind(x) ^bind(y) ^const(template) = 1+1+2+2 = 6
  //   ^bind(alive) ^assign = 1+6 = 7

  return cells.filter(([x, y]) => {
  // ^inv(filter) ^bind(x) ^bind(y) = 2+1+1 = 4
    let count = 0;
    // ^bind(count) ^assign ^const(0) = 1+6+1 = 8
    for (let dx = -1; dx <= 1; dx++) {
